397	/** Channel-owned messaging helpers for target parsing, routing, and payload shaping. */
398	export type ChannelMessagingAdapter = {
399	  normalizeTarget?: (raw: string) => string | undefined;
400	  /**
401	   * Canonical plugin-owned session conversation grammar.
402	   * Use this when the provider encodes thread or scoped-conversation semantics
403	   * inside `rawId` (for example Telegram topics or Feishu sender scopes).
404	   * Return `baseConversationId` and `parentConversationCandidates` here when
405	   * you can so parsing and inheritance stay in one place.
406	   * `parentConversationCandidates`, when present, should be ordered from the
407	   * narrowest parent to the broadest/base conversation.
408	   * Bundled plugins that need the same grammar before runtime bootstrap can
409	   * mirror this contract through a top-level `session-key-api.ts` surface.
410	   */
411	  resolveSessionConversation?: (params: { kind: "group" | "channel"; rawId: string }) => {
412	    id: string;
413	    threadId?: string | null;
414	    baseConversationId?: string | null;
415	    parentConversationCandidates?: string[];
416	  } | null;
417	  /**
418	   * Legacy compatibility hook for parent fallbacks when a plugin does not need
419	   * to customize `id` or `threadId`. Core only uses this when
420	   * `resolveSessionConversation(...)` does not return
421	   * `parentConversationCandidates`.
422	   */
423	  resolveParentConversationCandidates?: (params: {
424	    kind: "group" | "channel";
425	    rawId: string;
426	  }) => string[] | null;
427	  resolveSessionTarget?: (params: {
428	    kind: "group" | "channel";
429	    id: string;
430	    threadId?: string | null;
431	  }) => string | undefined;
432	  parseExplicitTarget?: (params: { raw: string }) => {
433	    to: string;
434	    threadId?: string | number;
435	    chatType?: ChatType;
436	  } | null;
437	  /**
438	   * Lightweight chat-type inference used before directory lookup so plugins can
439	   * steer peer-vs-group resolution without reimplementing host search flow.
440	   */
441	  inferTargetChatType?: (params: { to: string }) => ChatType | undefined;
442	  buildCrossContextComponents?: ChannelCrossContextComponentsFactory;
443	  enableInteractiveReplies?: (params: {
444	    cfg: OpenClawConfig;
445	    accountId?: string | null;
446	  }) => boolean;
447	  hasStructuredReplyPayload?: (params: { payload: ReplyPayload }) => boolean;
448	  targetResolver?: {
449	    looksLikeId?: (raw: string, normalized?: string) => boolean;
450	    hint?: string;
451	    /**
452	     * Plugin-owned fallback for explicit/native targets or post-directory-miss
453	     * resolution. This should complement directory lookup, not duplicate it.
454	     */
455	    resolveTarget?: (params: {
456	      cfg: OpenClawConfig;
457	      accountId?: string | null;
458	      input: string;
459	      normalized: string;
460	      preferredKind?: ChannelDirectoryEntryKind | "channel";
461	    }) => Promise<{
462	      to: string;
463	      kind: ChannelDirectoryEntryKind | "channel";
464	      display?: string;
465	      source?: "normalized" | "directory";
466	    } | null>;
467	  };
468	  formatTargetDisplay?: (params: {
469	    target: string;
470	    display?: string;
471	    kind?: ChannelDirectoryEntryKind;
472	  }) => string;
473	  /**
474	   * Provider-specific session-route builder used after target resolution.
475	   * Keep session-key orchestration in core and channel-native routing rules here.
476	   */
477	  resolveOutboundSessionRoute?: (params: {
478	    cfg: OpenClawConfig;
479	    agentId: string;
480	    accountId?: string | null;
481	    target: string;
482	    resolvedTarget?: {
483	      to: string;
484	      kind: ChannelDirectoryEntryKind | "channel";
485	      display?: string;
486	      source: "normalized" | "directory";
487	    };
488	    replyToId?: string | null;
489	    threadId?: string | number | null;
490	  }) => ChannelOutboundSessionRoute | Promise<ChannelOutboundSessionRoute | null> | null;
