1	export function stripNextcloudTalkTargetPrefix(raw: string): string | undefined {
2	  const trimmed = raw.trim();
3	  if (!trimmed) {
4	    return undefined;
5	  }
6	
7	  let normalized = trimmed;
8	
9	  if (normalized.startsWith("nextcloud-talk:")) {
10	    normalized = normalized.slice("nextcloud-talk:".length).trim();
11	  } else if (normalized.startsWith("nc-talk:")) {
12	    normalized = normalized.slice("nc-talk:".length).trim();
13	  } else if (normalized.startsWith("nc:")) {
14	    normalized = normalized.slice("nc:".length).trim();
15	  }
16	
17	  if (normalized.startsWith("room:")) {
18	    normalized = normalized.slice("room:".length).trim();
19	  }
20	
21	  if (!normalized) {
22	    return undefined;
23	  }
24	
25	  return normalized;
26	}
