28	export function normalizeNextcloudTalkMessagingTarget(raw: string): string | undefined {
29	  const normalized = stripNextcloudTalkTargetPrefix(raw);
30	  return normalized ? `nextcloud-talk:${normalized}`.toLowerCase() : undefined;
31	}
