33	export function looksLikeNextcloudTalkTargetId(raw: string): boolean {
34	  const trimmed = raw.trim();
35	  if (!trimmed) {
36	    return false;
37	  }
38	
39	  if (/^(nextcloud-talk|nc-talk|nc):/i.test(trimmed)) {
40	    return true;
41	  }
42	
43	  return /^[a-z0-9]{8,}$/i.test(trimmed);
44	}
