import {
  normalizePulseBoardAllowlist,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";
import type { PulseBoardGroupConfig } from "./types.js";
import type { PulseBoardInboundMessage } from "./types.js";

export function resolvePulseBoardGroupMatch(params: {
  groups?: Record<string, PulseBoardGroupConfig>;
  target: string;
}): {
  groupConfig: PulseBoardGroupConfig | undefined;
  wildcardConfig: PulseBoardGroupConfig | undefined;
} {
  const { groups, target } = params;
  if (!groups) {
    return { groupConfig: undefined, wildcardConfig: undefined };
  }
  const loweredTarget = target.toLowerCase();
  const directMatch = Object.entries(groups).find(
    ([key]) => key.toLowerCase() === loweredTarget,
  );
  const wildcardMatch = groups["*"];
  return {
    groupConfig: directMatch?.[1] ?? undefined,
    wildcardConfig: wildcardMatch ?? undefined,
  };
}

export function resolvePulseBoardRequireMention(params: {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
}): boolean {
  if (params.groupConfig?.requireMention !== undefined) {
    return params.groupConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  return true;
}

export function resolvePulseBoardGroupAccessGate(params: {
  groupPolicy: string;
  groupMatch: {
    groupConfig: PulseBoardGroupConfig | undefined;
    wildcardConfig: PulseBoardGroupConfig | undefined;
  };
}): { allowed: boolean; reason?: string } {
  const { groupPolicy, groupMatch } = params;
  if (groupPolicy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }
  if (groupPolicy === "open") {
    return { allowed: true };
  }
  // allowlist
  if (groupMatch.groupConfig || groupMatch.wildcardConfig) {
    return { allowed: true };
  }
  return { allowed: false, reason: "board not in allowlist" };
}

export function resolvePulseBoardGroupSenderAllowed(params: {
  groupPolicy: string;
  message: PulseBoardInboundMessage;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  if (params.groupPolicy === "open") {
    return true;
  }
  // Check inner (board-level) allowFrom first
  if (params.innerAllowFrom.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: params.innerAllowFrom,
      message: params.message,
    }).allowed;
  }
  // Fall back to outer (channel-level) group allowFrom
  if (params.outerAllowFrom.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: params.outerAllowFrom,
      message: params.message,
    }).allowed;
  }
  // No allowFrom configured at group level: allow by default (board access already gated)
  return true;
}

export function resolvePulseBoardMentionGate(params: {
  isGroup: boolean;
  requireMention: boolean;
  wasMentioned: boolean;
  hasControlCommand: boolean;
  allowTextCommands: boolean;
  commandAuthorized: boolean;
}): { shouldSkip: boolean; reason?: string } {
  if (!params.isGroup) {
    return { shouldSkip: false };
  }
  // Control commands bypass mention gate if authorized
  if (params.hasControlCommand && params.allowTextCommands && params.commandAuthorized) {
    return { shouldSkip: false };
  }
  if (params.requireMention && !params.wasMentioned) {
    return { shouldSkip: true, reason: "mention required" };
  }
  return { shouldSkip: false };
}

