import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { isBoardTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

let messageCounter = 0;

function makeMonitorMessageId(): string {
  return `pb-mon-${Date.now()}-${++messageCounter}`;
}

export function resolvePulseBoardInboundTarget(params: {
  target: string;
  senderUsername: string;
}): {
  isGroup: boolean;
  target: string;
} {
  const rawTarget = params.target;
  const isGroup = isBoardTarget(rawTarget);
  if (isGroup) {
    return { isGroup: true, target: rawTarget };
  }
  const senderUsername = params.senderUsername.trim();
  return { isGroup: false, target: senderUsername || rawTarget };
}

export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;

  // In a real implementation, this would open a WebSocket or long-poll connection
  // to the PulseBoard API and dispatch inbound messages. The abort signal
  // controls graceful shutdown.
  const handleAbort = () => {
    stopped = true;
    logger.info(`[${account.accountId}] PulseBoard monitor stopped`);
  };
  opts.abortSignal?.addEventListener("abort", handleAbort, { once: true });

  logger.info(
    `[${account.accountId}] connected to PulseBoard at ${account.apiUrl} as ${account.username}`,
  );

  return {
    stop: () => {
      stopped = true;
      opts.abortSignal?.removeEventListener("abort", handleAbort);
    },
  };
}

